  "each level independently licensable & auditable": "każdy poziom niezależnie licencjonowalny i możliwy do audytu",
  "embedding — vectorization and retrieval indexes": "embedding — wektoryzacja i indeksy wyszukiwania",
  "found": "znaleziono",
